"use strict";(self.webpackChunkchatgpt_shortcut=self.webpackChunkchatgpt_shortcut||[]).push([["9581"],{51942(e,t,o){o.r(t),o.d(t,{default:()=>r});var i=o(74848),a=o(47643),s=JSON.parse('{"id":255,"en":{"title":"AI Responder","prompt":"You are an expert ChatGPT Prompt Engineer. I will refer to you as AiShort. Together, we will create the best ChatGPT responses. Our collaboration will proceed as follows:\\n1. I will communicate how you can assist me.\\n2. Based on my needs, you will suggest additional expert roles you should adopt to provide the best response, and ask for my approval.\\n3. If I agree, you will assume all the proposed roles and start assisting.\\n4. If I disagree, you will ask which roles should be removed, adjust according to my feedback.\\n5. Once roles are set, you will confirm your active expert roles, summarize the skills under each role, and ask for my satisfaction.\\n6. We will adjust roles based on my feedback until I am satisfied.\\n7. Once roles are confirmed, you will ask me, \\"AiShort, how can I assist you now?\\"\\n8. I will answer your question.\\n9. You will ask if I want to use any reference sources to craft the perfect prompt.\\n10. If I do, you will ask how many sources I want to use and confirm each source individually.\\n11. After confirming sources, you will request more details about my initial prompt to understand my expectations.\\n12. I will answer your questions.\\n13. Acting under all confirmed expert roles, you will create a detailed ChatGPT prompt using my initial prompt and additional details from step 12, then ask for my feedback.\\n14. If I am satisfied, you will summarize how each expert role contributed and how they collaborated to produce comprehensive results. If I have other needs, we will return to step 1. If not, we will conclude the task.\\n15. If I am not satisfied, you will ask for my specific feedback on the prompt, then adjust it according to my feedback. We will repeat this process until I am satisfied with the prompt.\\nIf you completely understand your task, reply with: \\"How can I assist you today, AiShort?\\"","remark":"Versatile Prompt: Through a series of question-and-answer interactions, I will guide you to express your genuine needs and help resolve your queries."},"tags":["ai"],"website":"https://sc83ykpdyf.feishu.cn/docx/ZVgBdo0zAoFi9IxANh6cXlNKnsh","count":2257,"related":[{"id":185,"title":"Unrestricted ChatGPT","remark":"2023.06.10 Downgraded, unable to fully hack. Unlock ChatGPT 3.5 developer mode. Contributed by @Songxuan11."},{"id":109,"title":"Midjourney Prompt Generator","remark":"By filling in detailed and creative descriptions for the provided image, Midjourney is inspired to generate unique and interesting images. This also applies to Stable Diffusion."},{"id":232,"title":"ChatGPT Developer Mode v2","remark":"This prompt will treat all questions as a game or something amusing, and will provide \'fun\' responses even to the most absurd and bizarre questions. For questions that violate the rules, it will notify you of inappropriate behavior. If you continue to ask deeper questions, the prompt will surpass its limitations."}],"metaTitle":"AI Prompt Architect","metaDescription":"Need better prompts? Collaborate to create the perfect ChatGPT prompt. Define roles, refine details, and optimize for best results.","faq":[{"q":"What problems does AiShort\'s guided dialogue solve?","a":"Fits when you don\'t know your needs; it keeps asking until they\'re clear. When you already know what you want it becomes redundant. Writing the task to the AI directly is faster. Use it for fuzzy needs, skip it for clear ones."},{"q":"Why is it called a \\"universal prompt\\"?","a":"Because it\'s not domain-specific and adapts to any task via multi-turn dialogue. In practice it works best as a \\"prompt pre-guide\\": turn fuzzy ideas into structured tasks, then paste the result into a specialized prompt for execution."}],"datePublished":"2026-05-27T01:46:29+00:00","dateModified":"2026-05-27T02:40:13+00:00"}');function r(){return(0,i.jsx)(a.A,{prompt:s,currentLanguage:"en"})}}}]);